mapper.select:
SELECT 아이디사용여부 useStatus
FROM J_참여자관리_로그인정보
WHERE 아이디=#{memberUserID}

mapper.update:
UPDATE J_직원_계정 SET 비밀번호 = #{memberUserChangePW}, 비밀번호변경일 = GETDATE() WHERE 아이디 = #{memberUserID};
UPDATE J_직원 SET 전화번호 = #{memberPhoneNumber}, 수정일 = GETDATE() WHERE 아이디 = #{memberUserID};
IF EXISTS ( SELECT 1 FROM J_참여자관리_일일업무보고 WHERE 아이디 = #{memberUserID} AND 지점 = #{memberBranch} AND 업무보고일 = CONVERT(CHAR(10), GETDATE(), 23) ) BEGIN UPDATE J_참여자관리_일일업무보고 SET 금일일반취업 = #{memberTodayEmployment}, 금일알선취업 = #{memberTodayPlacement}, 금주일반취업 = #{memberToWeekEmployment}, 금주알선취업 = #{memberToWeekPlacement}, 금월일반취업 = #{memberToMonthEmployment}, 금월알선취업 = #{memberToMonthPlacement}, 금년일반취업 = #{memberToYearEmployment}, 금년알선취업 = #{memberToYearPlacement}, 실적수정일 = GETDATE() WHERE 아이디 = #{memberUserID} AND 지점 = #{memberBranch} AND 업무보고일 = CONVERT(CHAR(10), GETDATE(), 23) END ELSE BEGIN INSERT INTO J_참여자관리_일일업무보고 (지점, 아이디, 금일일반취업, 금일알선취업, 금주일반취업, 금주알선취업, 금월일반취업, 금월알선취업, 금년일반취업, 금년알선취업, 업무보고일) VALUES ( #{memberBranch}, #{memberUserID}, #{memberTodayEmployment}, #{memberTodayPlacement}, #{memberToWeekEmployment}, #{memberToWeekPlacement}, #{memberToMonthEmployment}, #{memberToMonthPlacement}, #{memberToYearEmployment}, #{memberToYearPlacement}, CONVERT(CHAR(10), GETDATE(), 23) ) END

mapper.select:
SELECT COUNT(*)
FROM J_참여자관리_로그인정보
WHERE 아이디 = #{memberUserID}

mapper.insert:
INSERT INTO J_직원 (아이디, 이름, 이메일, 전화번호, 현재재직상태, 등록일, 수정일)
VALUES (#{memberUserID}, #{memberUserName}, #{memberEmail}, #{memberPhoneNumber}, N'재직', GETDATE(), GETDATE());

INSERT INTO J_직원_계정 (아이디, 비밀번호, 계정상태)
VALUES (#{memberUserID}, #{memberUserPW}, N'승인대기');

INSERT INTO J_직원_재직 (아이디, 주부서코드, 지점명, 권한, 관리자권한)
VALUES (#{memberUserID},
        (SELECT 부서코드 FROM J_부서 WHERE 지점명 = #{memberBranch}),
        #{memberBranch}, N'상담', 0);

INSERT INTO J_직원_부서배치 (직원아이디, 부서코드, 주부서여부, 시작일)
VALUES (#{memberUserID},
        (SELECT 부서코드 FROM J_부서 WHERE 지점명 = #{memberBranch}), 1, GETDATE());

INSERT INTO J_직원_참여자관리_프로필 (직원아이디)
VALUES (#{memberUserID});


INSERT INTO J_직원_사이트접속 (직원아이디, 사이트코드, 부서코드, 접속허용, 사이트내권한)
VALUES (#{memberUserID}, N'COUNSEL', NULL, 1, NULL);

update.foreach:
UPDATE J_직원_참여자관리_프로필
SET
    조회순서 = #{index},
    일일업무일지발급여부 = #{memberDailyWorkDiaryIssuances[${index}], jdbcType=BOOLEAN}
WHERE
    직원아이디 = #{userId}
